var REGISTRY_BY_ID = Object.fromEntries(REGISTRY.map((c) => [c.id, c]));
var GROUPS = ["Primitives", "Motion", "Charts", "Navigation", "Overlay", "Feedback", "Data"];

// src/flags.ts
var FLAG_TO_PROP = {
  "--color": "color",
  "--variant": "variant",
  "--size": "size",
  "--radius": "radius",
  "--hover": "hoverEffect",
  "--shadow": "shadow",
  "--animation": "clickAnim",
  "--speed": "speed",
  "--uppercase": "uppercase",
  "--full-width": "fullWidth",
  "--duration": "duration",
  "--height": "height",
  "--shape": "shape",
  "--side": "side",
  "--padding": "padding"
};
function parseFlags(rawFlags) {
  const props = {};
  for (const raw of rawFlags) {
    const [keyPart, ...valueParts] = raw.split("=");
    const propKey = FLAG_TO_PROP[keyPart];
    if (!propKey) continue;
    if (valueParts.length === 0) {
      props[propKey] = true;
    } else {
      const value = valueParts.join("=");
      props[propKey] = isNaN(Number(value)) ? value : Number(value);
    }
  }
  return props;
}

// src/generate.ts
import fs3 from "fs-extra";
import path3 from "path";
import pc2 from "picocolors";
function hexToRgb(hex) {
  const clean = hex.replace("#", "");
  const r = parseInt(clean.slice(0, 2), 16);
  const g = parseInt(clean.slice(2, 4), 16);
  const b = parseInt(clean.slice(4, 6), 16);
  return `${r}, ${g}, ${b}`;
}
function generateButton(props) {
  const color = props.color ?? "#7F77DD";
  const rgb = hexToRgb(color);
  const variant = props.variant ?? "glow";
  const radius = props.radius ?? 8;
  const hoverEffect = props.hoverEffect ?? "lift";
  const shadow = props.shadow ?? "glow";
  const clickAnim = props.clickAnim ?? "ripple";
  const uppercase = props.uppercase ?? false;
  const fullWidth = props.fullWidth ?? false;
  const tsx = `// ForgeButton \u2014 generated by forge-ui CLI
// Edit this file freely \u2014 you own it.
// Re-generate with: npx forge-ui update button

import './ForgeButton.css'

interface ForgeButtonProps {
  children: React.ReactNode
  color?: string
  variant?: 'glow' | 'solid' | 'ghost' | 'outline' | 'soft' | 'spectrum'
  radius?: number
  uppercase?: boolean
  fullWidth?: boolean
  disabled?: boolean
  onClick?: () => void
}

export function ForgeButton({
  children,
  color = '${color}',
  variant = '${variant}',
  radius = ${radius},
  uppercase = ${uppercase},
  fullWidth = ${fullWidth},
  disabled = false,
  onClick,
}: ForgeButtonProps) {
  return (
    <button
      className={\`forge-btn forge-btn--\${variant}\${disabled ? ' forge-btn--disabled' : ''}\${fullWidth ? ' forge-btn--full' : ''}\`}
      style={{
        '--forge-color': color,
        '--forge-rgb': color,
        borderRadius: radius,
        textTransform: uppercase ? 'uppercase' : 'none',
      } as React.CSSProperties}
      disabled={disabled}
      onClick={onClick}
    >
      {children}
    </button>
  )
}
`;
  const css = `/* ForgeButton.css \u2014 generated by forge-ui CLI */
/* Edit freely \u2014 you own this file. */

.forge-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 7px;
  padding: 10px 20px;
  font-size: 13px;
  font-weight: 400;
  font-family: Inter, sans-serif;
  letter-spacing: -0.01em;
  border: 1px solid transparent;
  cursor: pointer;
  transition: all 0.2s ease;
  position: relative;
  overflow: hidden;
}

/* Glow variant \u2014 default */
.forge-btn--glow {
  background: rgba(${rgb}, 0.10);
  border-color: rgba(${rgb}, 0.28);
  color: rgba(${rgb}, 0.90);
}
.forge-btn--glow:hover {
  border-color: rgba(${rgb}, 0.55);
  box-shadow: 0 0 22px rgba(${rgb}, 0.25);
  ${hoverEffect === "lift" ? "transform: translateY(-2px);" : ""}
  ${hoverEffect === "scale" ? "transform: scale(1.04);" : ""}
}

/* Solid variant */
.forge-btn--solid {
  background: ${color};
  border-color: ${color};
  color: #ffffff;
}
.forge-btn--solid:hover {
  opacity: 0.88;
  ${hoverEffect === "lift" ? "transform: translateY(-2px);" : ""}
}

/* Ghost variant */
.forge-btn--ghost {
  background: transparent;
  border-color: rgba(255,255,255,0.1);
  color: rgba(240,237,232,0.5);
}
.forge-btn--ghost:hover {
  background: rgba(255,255,255,0.05);
  color: #f0ede8;
}

/* Outline variant */
.forge-btn--outline {
  background: transparent;
  border-color: rgba(${rgb}, 0.5);
  color: rgba(${rgb}, 0.9);
}

/* Soft variant */
.forge-btn--soft {
  background: rgba(${rgb}, 0.07);
  border-color: transparent;
  color: rgba(${rgb}, 0.9);
}

/* Disabled state */
.forge-btn--disabled {
  opacity: 0.4;
  cursor: not-allowed;
  pointer-events: none;
}

/* Full width */
.forge-btn--full {
  width: 100%;
}

/* Shadow: ${shadow} */
${shadow === "glow" ? `.forge-btn:hover { box-shadow: 0 0 20px rgba(${rgb}, 0.25), 0 4px 16px rgba(${rgb}, 0.12); }` : ""}
${shadow === "soft" ? `.forge-btn:hover { box-shadow: 0 6px 20px rgba(0,0,0,0.35); }` : ""}

/* Click animation: ${clickAnim} */
${clickAnim === "ripple" ? `
@keyframes forge-ripple {
  to { transform: scale(20); opacity: 0; }
}
.forge-btn .forge-ripple {
  position: absolute;
  border-radius: 50%;
  width: 10px;
  height: 10px;
  background: rgba(255,255,255,0.25);
  animation: forge-ripple 0.5s ease-out forwards;
  pointer-events: none;
}` : ""}
`;
  return { tsx, css };
}
function generatePlaceholder(componentId, displayName) {
  const tsx = `// ${displayName} \u2014 generated by forge-ui CLI v0.1.0
// Full file generation for this component is coming in v0.2.0.
// In the meantime, configure it visually at forgelabs.studio/playground
// and copy the output manually.

export function ${displayName}({ children }: { children?: React.ReactNode }) {
  return <div className="forge-${componentId}">{children}</div>
}
`;
  const css = `/* ${displayName}.css \u2014 placeholder */
.forge-${componentId} {}
`;
  return { tsx, css };
}
async function generateComponent(componentId, displayName, props, config) {
  const outputDir = path3.join(process.cwd(), config.output);
  await fs3.ensureDir(outputDir);
  let tsx;
  let css;
  if (componentId === "button") {
    ;
    ({ tsx, css } = generateButton(props));
  } else {
    ;
    ({ tsx, css } = generatePlaceholder(componentId, displayName));
  }
  const tsxPath = path3.join(outputDir, `${displayName}.tsx`);
  const cssPath = path3.join(outputDir, `${displayName}.css`);
  await fs3.writeFile(tsxPath, tsx, "utf8");
  await fs3.writeFile(cssPath, css, "utf8");
  console.log(pc2.green("  \u2713") + ` ${displayName}.tsx`);
  console.log(pc2.green("  \u2713") + ` ${displayName}.css`);
}

// src/commands/add.ts
async function runAdd(componentId, rawFlags) {
  console.log(pc3.bold(`
  forge-ui add ${componentId}
`));
  const meta = REGISTRY_BY_ID[componentId];
  if (!meta) {
    console.log(pc3.red(`  Unknown component: "${componentId}"`));
    console.log(pc3.dim("  Run npx forge-ui list to see available components.\n"));
    process.exit(1);
  }
  let config = await readConfig();
  if (!config) {
    config = createDefaultConfig();
    console.log(pc3.dim("  No forge.config.json found \u2014 creating one.\n"));
  }
  const flagProps = parseFlags(rawFlags);
  const props = { color: meta.defaultColor, ...flagProps };
  await generateComponent(componentId, meta.displayName, props, config);
  config.components[componentId] = props;
  await writeConfig(config);
  if (meta.deps?.length) {
    console.log(pc3.yellow(`
  Peer deps required: ${meta.deps.join(", ")}`));
  }
  console.log(pc3.dim(`
  Import with:`));
  console.log(pc3.cyan(`  import { ${meta.displayName} } from '@/components/forge/${meta.displayName}'
`));
}

// src/commands/list.ts
import pc4 from "picocolors";
async function runList() {
  console.log(pc4.bold("\n  FORGE.ui components\n"));
  const config = await readConfig();
  const installed = new Set(Object.keys(config?.components ?? {}));
  for (const group of GROUPS) {
    const components = REGISTRY.filter((c) => c.group === group);
    console.log(pc4.dim(`  ${group}`));
    for (const c of components) {
      const tick = installed.has(c.id) ? pc4.green("\u2713") : pc4.dim("\u25CB");
      console.log(`  ${tick} ${pc4.white(c.displayName.padEnd(22))} ${pc4.dim(c.description)}`);
    }
    console.log();
  }
}

// src/commands/update.ts
import pc5 from "picocolors";
async function runUpdate(componentId) {
  console.log(pc5.bold(`
  forge-ui update ${componentId}
`));
  const config = await readConfig();
  if (!config) {
    console.log(pc5.red("  No forge.config.json found. Run npx forge-ui init first.\n"));
    process.exit(1);
  }
  const savedProps = config.components[componentId];
  if (!savedProps) {
    console.log(pc5.red(`  "${componentId}" is not in forge.config.json.`));
    console.log(pc5.dim("  Run npx forge-ui add " + componentId + " first.\n"));
    process.exit(1);
  }
  const meta = REGISTRY_BY_ID[componentId];
  if (!meta) {
    console.log(pc5.red(`  Unknown component: "${componentId}"
`));
    process.exit(1);
  }
  await generateComponent(componentId, meta.displayName, savedProps, config);
  await writeConfig(config);
  console.log(pc5.dim("\n  Regenerated with original configuration.\n"));
}

// src/commands/remove.ts
import fs4 from "fs-extra";
import path4 from "path";
import pc6 from "picocolors";
async function runRemove(componentId) {
  console.log(pc6.bold(`
  forge-ui remove ${componentId}
`));
  const config = await readConfig();
  if (!config) {
    console.log(pc6.red("  No forge.config.json found.\n"));
    process.exit(1);
  }
  const meta = REGISTRY_BY_ID[componentId];
  if (!meta) {
    console.log(pc6.red(`  Unknown component: "${componentId}"
`));
    process.exit(1);
  }
  const outputDir = path4.join(process.cwd(), config.output);
  const tsxPath = path4.join(outputDir, `${meta.displayName}.tsx`);
  const cssPath = path4.join(outputDir, `${meta.displayName}.css`);
  if (await fs4.pathExists(tsxPath)) {
    await fs4.remove(tsxPath);
    console.log(pc6.red("  \u2715") + ` ${meta.displayName}.tsx`);
  }
  if (await fs4.pathExists(cssPath)) {
    await fs4.remove(cssPath);
    console.log(pc6.red("  \u2715") + ` ${meta.displayName}.css`);
  }
  delete config.components[componentId];
  await writeConfig(config);
  console.log(pc6.dim("\n  Removed from forge.config.json.\n"));
}

// src/index.ts
var program = new Command();
program.name("forge-ui").description("FORGE.ui \u2014 spectrum-aware React component library").version("0.1.0");
program.command("init").description("Create forge.config.json and forge-tokens.css").action(() => runInit());
program.command("add <component>").description("Add a component with optional flags").allowUnknownOption(true).action((component, _opts, cmd) => {
  const rawFlags = cmd.args.slice(1);
  runAdd(component, rawFlags);
});
program.command("list").description("List all available and installed components").action(() => runList());
program.command("update <component>").description("Regenerate a component using its saved configuration").action((component) => runUpdate(component));
program.command("remove <component>").description("Remove a component and its files").action((component) => runRemove(component));
program.parse();
